import java.io.Serializable;
import java.util.Objects;

public class EmployeePhoneId implements Serializable {

    private Integer employeeId;
    private Integer sortOrder;

    public Integer getEmployeeId() {
        return this.employeeId;
    }

    public void setEmployeeId(Integer employeeId) {
        this.employeeId = employeeId;
    }

    public Integer getSortOrder() {
        return this.sortOrder;
    }

    public void setSortOrder(Integer sortOrder) {
        this.sortOrder = sortOrder;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof EmployeePhone)) return false;
        final EmployeePhone employeePhone = (EmployeePhone) o;
        return Objects.equals(getEmployeeId(), employeePhone.getEmployeeId()) &&
                Objects.equals(getSortOrder(), employeePhone.getSortOrder());
    }

    @Override
    public int hashCode() {
        return Objects.hash(getEmployeeId(),
                getSortOrder());
    }
}
